'use client'

import TaskCard from './TaskCard/TaskCard'

type Todo = {
  userId: number
  id: number
  title: string
  completed: boolean
}

const TaskList = ({ todos }: { todos: Todo[] }) => {
  return (
    <div>
      <h1>Task List</h1>
      {todos.map((todo) => (
        <TaskCard key={todo.id} todo={todo} />
      ))}
    </div>
  )
}

export default TaskList